+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { TraitInstance } from '../../trait/types';
+import type { World } from '../../world';
+import { checkQueryWithRelations } from './check-query-with-relations';
+import { matchesPredicate } from './check-predicates';
+import type { QueryInstance } from '../types';
+
+export function updatePredicateQueries(
+    world: World,
+    entity: Entity,
+    queries: Set<QueryInstance>
+): void {
+    for (const query of queries) {
+        const matches = query.relationFilters?.length
+            ? checkQueryWithRelations(world, query, entity)
+            : query.check(world, entity);
+        if (query.predicateTrackers.length === 0) {
+            if (matches) query.add(entity);
+            else query.remove(world, entity);
+            continue;
+        }
+        const eid = getEntityId(entity);
+        let transitioned = false;
+        for (const tracker of query.predicateTrackers) {
+            const previous = tracker.states[eid] || false;
+            const current = matchesPredicate(world, entity, tracker.predicate);
+            tracker.states[eid] = current;
+            if (
+                (tracker.type === 'add' && !previous && current) ||
+                (tracker.type === 'remove' && previous && !current) ||
+                (tracker.type === 'change' && previous !== current)
+            ) transitioned = true;
+        }
+        if (matches && transitioned) query.add(entity);
+        else if (!matches) query.remove(world, entity);
+    }
+}
